    pub fn rollover_batched_state_merkle_tree<'info>(
        ctx: Context<'_, '_, '_, 'info, RolloverBatchedStateMerkleTree<'info>>,
        bump: u8,
    ) -> Result<()> {
        let account =
            BatchedMerkleTreeAccount::state_from_account_info(&ctx.accounts.old_state_merkle_tree)
