struct TestContext {
    rpc: LightProgramTest,
    payer: Keypair,
    config_pda: Pubkey,
    program_id: Pubkey,
}

impl TestContext {
    async fn new() -> Self {
        use light_account::derive_rent_sponsor_pda;

        let program_id = csdk_anchor_full_derived_test::ID;
        let mut config = ProgramTestConfig::new_v2(
            true,
            Some(vec![("csdk_anchor_full_derived_test", program_id)]),
        );
        config = config.with_light_protocol_events();

        let mut rpc = LightProgramTest::new(config).await.unwrap();
        let payer = rpc.get_payer().insecure_clone();

        let program_data_pda = setup_mock_program_data(&mut rpc, &payer, &program_id);

        // Derive rent sponsor PDA for this program
        let (rent_sponsor, _) = derive_rent_sponsor_pda(&program_id);

        // Fund the rent sponsor PDA so it can pay for decompression
        rpc.airdrop_lamports(&rent_sponsor, 10_000_000_000)
            .await
            .expect("Airdrop to rent sponsor should succeed");

        let (init_config_ix, config_pda) = InitializeRentFreeConfig::new(
            &program_id,
            &payer.pubkey(),
            &program_data_pda,
            rent_sponsor,
            payer.pubkey(),
        )
        .build();

        rpc.create_and_send_transaction(&[init_config_ix], &payer.pubkey(), &[&payer])
            .await
            .expect("Initialize config should succeed");

        Self {
            rpc,
            payer,
            config_pda,
            program_id,
        }
    }

    /// Reads a SinglePubkeyRecord from a PDA and asserts it matches expected values.
    async fn assert_single_pubkey_record(
        &mut self,
        pda: &Pubkey,
        expected_owner: Pubkey,
        expected_counter: u64,
        label: &str,
    ) {
        let account = self
            .rpc
            .get_account(*pda)
            .await
            .unwrap()
            .unwrap_or_else(|| panic!("{label} account should exist"));
        let record: csdk_anchor_full_derived_test::SinglePubkeyRecord =
            anchor_lang::AccountDeserialize::try_deserialize(&mut &account.data[..]).unwrap();
        let expected = csdk_anchor_full_derived_test::SinglePubkeyRecord {
            compression_info: shared::expected_compression_info(&record.compression_info),
            owner: expected_owner,
            counter: expected_counter,
        };
        assert_eq!(record, expected, "{label} should match expected");
    }

    /// Runs the full compression/decompression lifecycle for a single PDA.
    async fn assert_lifecycle<S>(&mut self, pda: &Pubkey, seeds: S, owner: Pubkey)
    where
        S: IntoVariant<LightAccountVariant>,
    {
        // Warp to trigger compression
        self.rpc
            .warp_slot_forward(SLOTS_PER_EPOCH * 30)
            .await
            .unwrap();
        shared::assert_onchain_closed(&mut self.rpc, pda, "pda").await;

        // Get account interface
        let account_interface = self
            .rpc
            .get_account_interface(pda, None)
            .await
            .expect("failed to get account interface")
            .value
            .expect("account should exist");
        assert!(
            account_interface.is_cold(),
            "Account should be cold after compression"
        );

        // Build variant from seeds and account data
        let variant = seeds
            .into_variant(&account_interface.account.data[8..])
            .expect("Seed verification failed");

        // Build PdaSpec
        let spec = PdaSpec::new(account_interface.clone(), variant, self.program_id);

        // Create AccountSpec slice
        let specs: Vec<AccountSpec<LightAccountVariant>> = vec![AccountSpec::Pda(spec)];

        // Create and execute decompression
        let decompress_instructions =
            create_load_instructions(&specs, self.payer.pubkey(), self.config_pda, &self.rpc)
                .await
                .expect("create_load_instructions should succeed");

        self.rpc
            .create_and_send_transaction(
                &decompress_instructions,
                &self.payer.pubkey(),
                &[&self.payer],
            )
            .await
            .expect("Decompression should succeed");

        // Verify account is back on-chain
        shared::assert_onchain_exists(&mut self.rpc, pda, "pda").await;
        self.assert_single_pubkey_record(pda, owner, 0, "after decompression")
            .await;
    }

    /// Setup a mint for token-based tests.
    /// Returns (mint_pubkey, compression_address, ata_pubkeys, mint_seed_keypair)
    #[allow(dead_code)]
    async fn setup_mint(&mut self) -> (Pubkey, [u8; 32], Vec<Pubkey>, Keypair) {
        shared::setup_create_mint(
            &mut self.rpc,
            &self.payer,
            self.payer.pubkey(), // mint_authority
            9,                   // decimals
            vec![],              // no recipients initially
        )
        .await
    }

    /// Decompress a cold PDA. Does NOT warp - caller must warp first.
    async fn decompress_pda<S>(&mut self, pda: &Pubkey, seeds: S)
    where
        S: IntoVariant<LightAccountVariant>,
    {
        // Get account interface
        let account_interface = self
            .rpc
            .get_account_interface(pda, None)
            .await
            .expect("failed to get account interface")
            .value
            .expect("account interface should exist");
        assert!(
            account_interface.is_cold(),
            "Account should be cold after compression"
        );

        // Build variant from seeds and account data
        let variant = seeds
            .into_variant(&account_interface.account.data[8..])
            .expect("Seed verification failed");

        // Build PdaSpec
        let spec = PdaSpec::new(account_interface.clone(), variant, self.program_id);

        // Create AccountSpec slice
        let specs: Vec<AccountSpec<LightAccountVariant>> = vec![AccountSpec::Pda(spec)];

        // Create and execute decompression
        let decompress_instructions =
            create_load_instructions(&specs, self.payer.pubkey(), self.config_pda, &self.rpc)
                .await
                .expect("create_load_instructions should succeed");

        self.rpc
            .create_and_send_transaction(
                &decompress_instructions,
                &self.payer.pubkey(),
                &[&self.payer],
            )
            .await
            .expect("Decompression should succeed");

        // Verify account is back on-chain
        shared::assert_onchain_exists(&mut self.rpc, pda, "pda").await;
    }

    /// Decompress a cold token vault. Does NOT warp - caller must warp first.
    async fn decompress_token_vault(
        &mut self,
        vault_pda: &Pubkey,
        build_variant: impl FnOnce(light_token_interface::state::Token) -> LightAccountVariant,
        expected_mint: Pubkey,
        expected_owner: Pubkey,
        expected_amount: u64,
    ) {
        use light_client::interface::AccountInterface;

        // Fetch token account interface
        let vault_interface = self
            .rpc
            .get_token_account_interface(vault_pda, None)
            .await
            .expect("get_token_account_interface should succeed")
            .value
            .expect("token account interface should exist");
        assert!(vault_interface.is_cold(), "Token vault should be cold");

        // Deserialize token data
        let token = light_token_interface::state::Token::deserialize(
            &mut &vault_interface.account.data[..],
        )
        .expect("Failed to parse Token");

        // Build variant using provided closure
        let vault_variant = build_variant(token);

        // Get compressed context
        let vault_compressed = vault_interface
            .compressed()
            .expect("cold vault must have compressed data");

        // Convert to AccountInterface with compressed account
        let vault_interface_for_pda = AccountInterface {
            key: vault_interface.key,
            account: vault_interface.account.clone(),
            cold: Some(vault_compressed.account.clone()),
        };

        // Get mint interface - must be decompressed before token vault
        let mint_interface = AccountInterface::from(
            self.rpc
                .get_mint_interface(&expected_mint, None)
                .await
                .expect("failed to get mint")
                .value
                .expect("mint should exist"),
        );

        // Create PdaSpec and decompress - mint first, then vault
        let vault_spec = PdaSpec::new(vault_interface_for_pda, vault_variant, self.program_id);
        let specs: Vec<AccountSpec<LightAccountVariant>> = vec![
            AccountSpec::Mint(mint_interface),
            AccountSpec::Pda(vault_spec),
        ];

        let decompress_instructions =
            create_load_instructions(&specs, self.payer.pubkey(), self.config_pda, &self.rpc)
                .await
                .expect("create_load_instructions should succeed");

        self.rpc
            .create_and_send_transaction(
                &decompress_instructions,
                &self.payer.pubkey(),
                &[&self.payer],
            )
            .await
            .expect("Token vault decompression should succeed");

        // Verify back on-chain
        shared::assert_onchain_exists(&mut self.rpc, vault_pda, "token_vault").await;

        // Full-struct Token assertion after decompression
        {
            use light_token_interface::state::token::{
                AccountState, Token, ACCOUNT_TYPE_TOKEN_ACCOUNT,
            };
            let vault_account = self.rpc.get_account(*vault_pda).await.unwrap().unwrap();
            let vault_data: Token =
                borsh::BorshDeserialize::deserialize(&mut &vault_account.data[..]).unwrap();
            let expected = Token {
                mint: expected_mint.into(),
                owner: expected_owner.into(),
                amount: expected_amount,
                delegate: None,
                state: AccountState::Initialized,
                is_native: None,
                delegated_amount: 0,
                close_authority: None,
                account_type: ACCOUNT_TYPE_TOKEN_ACCOUNT,
                extensions: vault_data.extensions.clone(),
            };
            assert_eq!(
                vault_data, expected,
                "Token vault should match after decompression"
            );
        }
    }
}

