/// Tests D8MultiRentfree: Multiple #[light_account(init)] fields of same type
#[tokio::test]
async fn test_d8_multi_rentfree() {
    use csdk_anchor_full_derived_test::d8_builder_paths::D8MultiRentfreeParams;

    let mut ctx = TestContext::new().await;
    let owner = Keypair::new().pubkey();
    let id1 = 111u64;
    let id2 = 222u64;

    // Derive PDAs
    let (pda1, _) = Pubkey::find_program_address(
        &[b"d8_multi_1", owner.as_ref(), id1.to_le_bytes().as_ref()],
        &ctx.program_id,
    );
    let (pda2, _) = Pubkey::find_program_address(
        &[b"d8_multi_2", owner.as_ref(), id2.to_le_bytes().as_ref()],
        &ctx.program_id,
    );

    // Get proof for both PDAs
    let proof_result = get_create_accounts_proof(
        &ctx.rpc,
        &ctx.program_id,
        vec![
            CreateAccountsProofInput::pda(pda1),
            CreateAccountsProofInput::pda(pda2),
        ],
    )
    .await
    .unwrap();

    // Build instruction
    let accounts = csdk_anchor_full_derived_test::accounts::D8MultiRentfree {
        fee_payer: ctx.payer.pubkey(),
        compression_config: ctx.config_pda,
        pda_rent_sponsor: program_rent_sponsor(),
        d8_multi_record1: pda1,
        d8_multi_record2: pda2,
        system_program: solana_sdk::system_program::ID,
    };

    let instruction_data = csdk_anchor_full_derived_test::instruction::D8MultiRentfree {
        params: D8MultiRentfreeParams {
            create_accounts_proof: proof_result.create_accounts_proof,
            owner,
            id1,
            id2,
        },
    };

    let instruction = Instruction {
        program_id: ctx.program_id,
        accounts: [
            accounts.to_account_metas(None),
            proof_result.remaining_accounts,
        ]
        .concat(),
        data: instruction_data.data(),
    };

    ctx.rpc
        .create_and_send_transaction(&[instruction], &ctx.payer.pubkey(), &[&ctx.payer])
        .await
        .expect("D8MultiRentfree instruction should succeed");

    // Verify both accounts exist on-chain
    shared::assert_onchain_exists(&mut ctx.rpc, &pda1, "pda1").await;
    shared::assert_onchain_exists(&mut ctx.rpc, &pda2, "pda2").await;
    ctx.assert_single_pubkey_record(&pda1, owner, 0, "pda1 after init")
        .await;
    ctx.assert_single_pubkey_record(&pda2, owner, 0, "pda2 after init")
        .await;

    // Full lifecycle: compression + decompression (multi-PDA, one at a time)
    use csdk_anchor_full_derived_test::csdk_anchor_full_derived_test::{
        D8MultiRecord1Seeds, D8MultiRecord2Seeds,
    };

    // Warp to trigger compression
    ctx.rpc
        .warp_slot_forward(SLOTS_PER_EPOCH * 30)
        .await
        .unwrap();
    shared::assert_onchain_closed(&mut ctx.rpc, &pda1, "pda1").await;
    shared::assert_onchain_closed(&mut ctx.rpc, &pda2, "pda2").await;

    // Decompress first account
    let interface1 = ctx
        .rpc
        .get_account_interface(&pda1, None)
        .await
        .unwrap()
        .value
        .unwrap();
    let variant1 = D8MultiRecord1Seeds { owner, id1 }
        .into_variant(&interface1.account.data[8..])
        .unwrap();
    let spec1 = PdaSpec::new(interface1.clone(), variant1, ctx.program_id);
    let specs: Vec<AccountSpec<LightAccountVariant>> = vec![AccountSpec::Pda(spec1)];
    let decompress_instructions =
        create_load_instructions(&specs, ctx.payer.pubkey(), ctx.config_pda, &ctx.rpc)
            .await
            .unwrap();
    ctx.rpc
        .create_and_send_transaction(&decompress_instructions, &ctx.payer.pubkey(), &[&ctx.payer])
        .await
        .unwrap();
    shared::assert_onchain_exists(&mut ctx.rpc, &pda1, "pda1").await;
    ctx.assert_single_pubkey_record(&pda1, owner, 0, "pda1 after decompression")
        .await;

    // Decompress second account
    let interface2 = ctx
        .rpc
        .get_account_interface(&pda2, None)
        .await
        .unwrap()
        .value
        .unwrap();
    let variant2 = D8MultiRecord2Seeds { owner, id2 }
        .into_variant(&interface2.account.data[8..])
        .unwrap();
    let spec2 = PdaSpec::new(interface2.clone(), variant2, ctx.program_id);
    let specs: Vec<AccountSpec<LightAccountVariant>> = vec![AccountSpec::Pda(spec2)];
    let decompress_instructions =
        create_load_instructions(&specs, ctx.payer.pubkey(), ctx.config_pda, &ctx.rpc)
            .await
            .unwrap();
    ctx.rpc
        .create_and_send_transaction(&decompress_instructions, &ctx.payer.pubkey(), &[&ctx.payer])
        .await
        .unwrap();
    shared::assert_onchain_exists(&mut ctx.rpc, &pda2, "pda2").await;
    ctx.assert_single_pubkey_record(&pda2, owner, 0, "pda2 after decompression")
        .await;
}

/// Tests D8All: Multiple #[light_account(init)] fields of different types
